        ngx.status = 401
        ngx.say("Unauthorized")
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Decode the token to get user information
    local decoded, err = jwt.decode_verify(token, secret_key, {algorithm = "HS256"})
    if not decoded then
